def depth_max(s):
    depth, max_depth = 0, 0
    for bracket in s:
        if bracket == '[':
            depth += 1
            max_depth = max(max_depth, depth)
        elif bracket == ']':
            if not depth:
                return -1  # edge case: closing bracket without opening one
            depth -= 1
    return max_depth
